package com.oneil.wellness.walkplanner.calendar.provider.google;
import com.fasterxml.jackson.databind.JsonNode;import com.oneil.wellness.walkplanner.calendar.model.*;import java.time.*;import java.util.*;import org.springframework.stereotype.Component;
@Component
public class GoogleCalendarEventMapper {
 public Optional<CalendarEvent> map(JsonNode node,String opaqueCalendarId,String calendarZone){if("cancelled".equals(node.path("status").asText()))return Optional.empty();JsonNode start=node.path("start"),end=node.path("end");boolean allDay=start.hasNonNull("date");String zone=first(start.path("timeZone").asText(null),calendarZone,"UTC");OffsetDateTime from=allDay?LocalDate.parse(start.path("date").asText()).atStartOfDay(ZoneId.of(zone)).toOffsetDateTime():OffsetDateTime.parse(start.path("dateTime").asText());OffsetDateTime to=allDay?LocalDate.parse(end.path("date").asText()).atStartOfDay(ZoneId.of(zone)).toOffsetDateTime():OffsetDateTime.parse(end.path("dateTime").asText());String eventId=node.path("id").asText();String recurring=node.path("recurringEventId").asText(null);String original=node.path("originalStartTime").path(allDay?"date":"dateTime").asText(from.toInstant().toString());String identity=(recurring==null?eventId:recurring);String occurrence=allDay?original:parseOccurrence(original);String title=node.path("summary").asText("Busy");boolean busy=!"transparent".equals(node.path("transparency").asText());return Optional.of(new CalendarEvent("google:"+opaqueCalendarId+":"+identity+":"+occurrence,title,from,to,busy,CalendarSource.GOOGLE,CalendarProviderType.GOOGLE,identity,opaqueCalendarId,occurrence,zone,allDay));}
 private String parseOccurrence(String value){try{return OffsetDateTime.parse(value).toInstant().toString();}catch(Exception e){return value;}}private String first(String... values){return Arrays.stream(values).filter(v->v!=null&&!v.isBlank()).findFirst().orElse("UTC");}
}
